import { strictEqual, ok } from "node:assert";
import { withDb } from "../src/db.mjs";
import { ensureSchema } from "../src/schema.mjs";
import { createAccounts, getAccounts, updateAccounts, deleteAccounts } from "../src/accounts.mjs";

await withDb(async (client) => {
  await ensureSchema(client);

  const created = await createAccounts(client, {
    accountId: "test-accountId", name: "test-name", tier: "strategic", status: "active",
  });
  ok(created.accountId, "create returns a document with an id");

  // verify directly in the live DB (doc is JSONB)
  const liveRow = (await client.query('SELECT doc FROM accounts WHERE account_id = $1', [created.accountId])).rows[0];
